class Solution {
public:
    int numPairsDivisibleBy60(vector<int>& time) {
        int count = 0;
        vector<int> freq(60, 0);
        for (int t : time) {
            int remainder = t % 60;
            count += freq[(60 - remainder) % 60];
            freq[remainder]++;
        }
        return count;
    }
};

